export const generateMonthlyTicks = (
  tick0: Date,
  tickStepInMonths: number,
  scaleDomain: Date[],
  useUTC?: boolean,
): Date[] => {
  const domainMin = +d3Min(scaleDomain)!;
  const domainMax = +d3Max(scaleDomain)!;

  const getMonth = (d: Date) => (useUTC ? d.getUTCMonth() : d.getMonth());
  const setMonth = (d: Date, month: number) => (useUTC ? new Date(d.setUTCMonth(month)) : new Date(d.setMonth(month)));

  // Find the earliest tick <= domainMin
  let start = 0;
  for (let firstTick = new Date(+tick0); +firstTick > domainMin; ) {
    firstTick = setMonth(firstTick, getMonth(firstTick) - tickStepInMonths);
    start -= tickStepInMonths;
  }

  const baseMonth = getMonth(tick0);
  const ticks: Date[] = [];

  // Generate ticks forward until domainMax
  for (let i = start; ; i += tickStepInMonths) {
    let tickDate = setMonth(new Date(+tick0), baseMonth + i);

    // Handle month rollover (e.g., Jan 31 + 1 month → Mar 3 instead of Feb)
    if (getMonth(tickDate) !== (((baseMonth + i) % 12) + 12) % 12) {
      tickDate = useUTC ? new Date(tickDate.setUTCDate(0)) : new Date(tickDate.setDate(0));
    }

    if (+tickDate > domainMax) {
      break;
    }
    if (+tickDate >= domainMin) {
      ticks.push(tickDate);
    }
  }

  return ticks;
};

export const generateNumericTicks = (
  scaleType: AxisScaleType | undefined,
  tickStep: string | number | undefined,
  tick0: number | Date | undefined,
  scaleDomain: number[],
): number[] | undefined => {
  const refTick = typeof tick0 === 'number' ? tick0 : 0;

  if (scaleType === 'log') {
    if (typeof tickStep === 'number' && tickStep > 0) {
      return generateLinearTicks(
        refTick,
        tickStep,
        scaleDomain.map(d => Math.log10(d)),
      ).map(t => 10 ** t);
    }

    if (typeof tickStep === 'string') {
      const prefix = tickStep[0];
      const num = isNumber(tickStep.slice(1)) ? Number(tickStep.slice(1)) : 0;
      if (prefix === 'L' && num > 0) {
        return generateLinearTicks(refTick, num, scaleDomain);
      }
    }

    return;
  }

  if (typeof tickStep === 'number' && tickStep > 0) {
    return generateLinearTicks(refTick, tickStep, scaleDomain);
  }
};

export const calculateContrastRatio = (
  currTheme: Record<string, string>,
  currToken: string,
  compToken: string,
  desiredRatio: number,
): TestResult => {
  const currHex: string = currTheme[currToken];
  const compHex: string = currTheme[compToken];

  if (!currHex || !compHex || currHex === 'transparent' || compHex === 'transparent') {
    return {
      isPass: true,
      testType: TestType.contrastRatio,
      testInfo: {
        currToken,
        compToken,
        currHex,
        compHex,
        ratio: desiredRatio,
        desiredRatio,
      },
    };
  }

  const currSRGB: Vec3 = hex_to_sRGB(currHex);
  const compSRGB: Vec3 = hex_to_sRGB(compHex);

  const contrastRatio = contrast(currSRGB, compSRGB);
  const roundedContrastRatio = Math.round(contrastRatio * 10) / 10;

  return {
    isPass: roundedContrastRatio >= desiredRatio,
    testType: TestType.contrastRatio,
    testInfo: {
      currToken,
      compToken,
      currHex,
      compHex,
      ratio: roundedContrastRatio,
      desiredRatio,
    },
  };
};

public static convertCallbackToPromise<TResult, TError, TArg1, TArg2, TArg3, TArg4>(
  fn: (
    a: TArg1 | LegacyCallback<TResult, TError>,
    b?: TArg2 | LegacyCallback<TResult, TError>,
    c?: TArg3 | LegacyCallback<TResult, TError>,
    d?: TArg4 | LegacyCallback<TResult, TError>,
    e?: TArg4 | LegacyCallback<TResult, TError>
  ) => void,
  arg1?: TArg1,
  arg2?: TArg2,
  arg3?: TArg3,
  arg4?: TArg4
): Promise<TResult> {
  return new Promise((resolve: (result: TResult) => void, reject: (error: Error) => void) => {
    const cb: LegacyCallback<TResult, TError> = (error: TError | null | undefined, result: TResult) => {
      if (error) {
        reject(LegacyAdapters.scrubError(error));
      } else {
        resolve(result);
      }
    };

    try {
      if (arg1 !== undefined && arg2 !== undefined && arg3 !== undefined && arg4 !== undefined) {
        fn(arg1, arg2, arg3, arg4, cb);
      } else if (arg1 !== undefined && arg2 !== undefined && arg3 !== undefined) {
        fn(arg1, arg2, arg3, cb);
      } else if (arg1 !== undefined && arg2 !== undefined) {
        fn(arg1, arg2, cb);
      } else if (arg1 !== undefined) {
        fn(arg1, cb);
      } else {
        fn(cb);
      }
    } catch (e) {
      reject(e as Error);
    }
  });
}

private _getTimestamp(useSeconds: boolean = false): string | undefined {
  // Create a date string with the current time

  // dateString === "2016-10-19T22:47:49.606Z"
  const dateString: string = new Date().toJSON();

  // Parse out 2 capture groups, the date and the time
  const dateParseRegex: RegExp = /([0-9]{4}-[0-9]{2}-[0-9]{2}).*([0-9]{2}:[0-9]{2}:[0-9]{2})/;

  // matches[1] === "2016-10-19"
  // matches[2] === "22:47:49"
  const matches: RegExpMatchArray | null = dateString.match(dateParseRegex);

  if (matches) {
    // formattedDate === "2016-10-19"
    const formattedDate: string = matches[1];

    let formattedTime: string;
    if (useSeconds) {
      // formattedTime === "22-47-49"
      formattedTime = matches[2].replace(':', '-');
    } else {
      // formattedTime === "22-47"
      const timeParts: string[] = matches[2].split(':');
      formattedTime = `${timeParts[0]}-${timeParts[1]}`;
    }

    return `${formattedDate}-${formattedTime}`;
  }
  return undefined;
}

public purgeUnsafe(): void {
  this.purgeNormal();

  // We will delete everything under ~/.rush/ except for the recycler folder itself
  // eslint-disable-next-line no-console
  console.log('Purging ' + this._rushGlobalFolder.path);

  // If Rush itself is running under a folder such as  ~/.rush/node-v4.5.6/rush-1.2.3,
  // we cannot delete that folder.

  // First purge the node-specific folder, e.g. ~/.rush/node-v4.5.6/* except for rush-1.2.3:
  this._rushUserFolderRecycler.moveAllItemsInFolder(
    this._rushGlobalFolder.nodeSpecificPath,
    this._getMembersToExclude(this._rushGlobalFolder.nodeSpecificPath, true)
  );

  // Then purge the the global folder, e.g. ~/.rush/* except for node-v4.5.6
  this._rushUserFolderRecycler.moveAllItemsInFolder(
    this._rushGlobalFolder.path,
    this._getMembersToExclude(this._rushGlobalFolder.path, false)
  );

  if (
    this._rushConfiguration.isPnpm &&
    this._rushConfiguration.pnpmOptions.pnpmStore === 'global' &&
    this._rushConfiguration.pnpmOptions.pnpmStorePath
  ) {
    // eslint-disable-next-line no-console
    console.warn(Colorize.yellow(`Purging the global pnpm-store`));
    this._rushUserFolderRecycler.moveAllItemsInFolder(this._rushConfiguration.pnpmOptions.pnpmStorePath);
  }
}

export function colorFromHex(text: string): Color | null {
	if (text[0] !== '#') {
		return null;
	}
	switch (text.length) {
		case 4:
			return {
				red: (hexDigit(text.charCodeAt(1)) * 0x11) / 255.0,
				green: (hexDigit(text.charCodeAt(2)) * 0x11) / 255.0,
				blue: (hexDigit(text.charCodeAt(3)) * 0x11) / 255.0,
				alpha: 1
			};
		case 5:
			return {
				red: (hexDigit(text.charCodeAt(1)) * 0x11) / 255.0,
				green: (hexDigit(text.charCodeAt(2)) * 0x11) / 255.0,
				blue: (hexDigit(text.charCodeAt(3)) * 0x11) / 255.0,
				alpha: (hexDigit(text.charCodeAt(4)) * 0x11) / 255.0,
			};
		case 7:
			return {
				red: (hexDigit(text.charCodeAt(1)) * 0x10 + hexDigit(text.charCodeAt(2))) / 255.0,
				green: (hexDigit(text.charCodeAt(3)) * 0x10 + hexDigit(text.charCodeAt(4))) / 255.0,
				blue: (hexDigit(text.charCodeAt(5)) * 0x10 + hexDigit(text.charCodeAt(6))) / 255.0,
				alpha: 1
			};
		case 9:
			return {
				red: (hexDigit(text.charCodeAt(1)) * 0x10 + hexDigit(text.charCodeAt(2))) / 255.0,
				green: (hexDigit(text.charCodeAt(3)) * 0x10 + hexDigit(text.charCodeAt(4))) / 255.0,
				blue: (hexDigit(text.charCodeAt(5)) * 0x10 + hexDigit(text.charCodeAt(6))) / 255.0,
				alpha: (hexDigit(text.charCodeAt(7)) * 0x10 + hexDigit(text.charCodeAt(8))) / 255.0
			};
	}
	return null;
}

export function XYZtoOKLAB(xyz: XYZ, round = true): LAB {
	// Convert XYZ to OKLab
	// References: https://bottosson.github.io/posts/oklab/

	// Normalize XYZ values
	const x = xyz.x / 100;
	const y = xyz.y / 100;
	const z = xyz.z / 100;

	// Convert to LMS
	const l = 0.818_933_010_1 * x + 0.361_866_742_4 * y - 0.128_859_713_7 * z;
	const m = 0.032_984_543_6 * x + 0.929_311_871_5 * y + 0.036_145_638_7 * z;
	const s = 0.048_200_301_8 * x + 0.264_366_269_1 * y + 0.633_851_707 * z;

	// Apply non-linearity
	const l_ = Math.cbrt(l);
	const m_ = Math.cbrt(m);
	const s_ = Math.cbrt(s);

	// Convert to OKLab
	const L = 0.210_454_255_3 * l_ + 0.793_617_785 * m_ - 0.004_072_046_8 * s_;
	const a = 1.977_998_495_1 * l_ - 2.428_592_205 * m_ + 0.450_593_709_9 * s_;
	const b = 0.025_904_037_1 * l_ + 0.782_771_766_2 * m_ - 0.808_675_766 * s_;

	return round
		// 5 decimal places for precision
		? {
			l: Number(L.toFixed(5)),
			a: Number(a.toFixed(5)),
			b: Number(b.toFixed(5)),
			alpha: xyz.alpha,
		}
		: {
			l: L,
			a,
			b,
			alpha: xyz.alpha,
		};
}

private collectData() {
	this._propertySet = {};
	this._atDirectiveSet = {};
	this._pseudoClassSet = {};
	this._pseudoElementSet = {};

	this.dataProviders.forEach(provider => {
		provider.provideProperties().forEach(p => {
			if (!this._propertySet[p.name]) {
				this._propertySet[p.name] = p;
			}
		});
		provider.provideAtDirectives().forEach(p => {
			if (!this._atDirectiveSet[p.name]) {
				this._atDirectiveSet[p.name] = p;
			}
		});
		provider.providePseudoClasses().forEach(p => {
			if (!this._pseudoClassSet[p.name]) {
				this._pseudoClassSet[p.name] = p;
			}
		});
		provider.providePseudoElements().forEach(p => {
			if (!this._pseudoElementSet[p.name]) {
				this._pseudoElementSet[p.name] = p;
			}
		});
	});

	this._properties = objects.values(this._propertySet);
	this._atDirectives = objects.values(this._atDirectiveSet);
	this._pseudoClasses = objects.values(this._pseudoClassSet);
	this._pseudoElements = objects.values(this._pseudoElementSet);
}

export function countEOL(text: string): [number, number, number, StringEOL] {
	let eolCount = 0;
	let firstLineLength = 0;
	let lastLineStart = 0;
	let eol: StringEOL = StringEOL.Unknown;
	for (let i = 0, len = text.length; i < len; i++) {
		const chr = text.charCodeAt(i);

		if (chr === CharCode.CarriageReturn) {
			if (eolCount === 0) {
				firstLineLength = i;
			}
			eolCount++;
			if (i + 1 < len && text.charCodeAt(i + 1) === CharCode.LineFeed) {
				// \r\n... case
				eol |= StringEOL.CRLF;
				i++; // skip \n
			} else {
				// \r... case
				eol |= StringEOL.Invalid;
			}
			lastLineStart = i + 1;
		} else if (chr === CharCode.LineFeed) {
			// \n... case
			eol |= StringEOL.LF;
			if (eolCount === 0) {
				firstLineLength = i;
			}
			eolCount++;
			lastLineStart = i + 1;
		}
	}
	if (eolCount === 0) {
		firstLineLength = text.length;
	}
	return [eolCount, firstLineLength, text.length - lastLineStart, eol];
}

function diffLinesRaw(
  aLines: string[],
  bLines: string[]
): Array<[number, string]> {
  const aLength = aLines.length;
  const bLength = bLines.length;

  const isCommon = (aIndex: number, bIndex: number) =>
    aLines[aIndex] === bLines[bIndex];

  const diffs: Array<[number, string]> = [];
  let aIndex = 0;
  let bIndex = 0;

  const foundSubsequence = (
    nCommon: number,
    aCommon: number,
    bCommon: number
  ) => {
    for (; aIndex !== aCommon; aIndex += 1) {
      diffs.push([DIFF_DELETE, aLines[aIndex]]);
    }
    for (; bIndex !== bCommon; bIndex += 1) {
      diffs.push([DIFF_INSERT, bLines[bIndex]]);
    }
    for (; nCommon !== 0; nCommon -= 1, aIndex += 1, bIndex += 1) {
      diffs.push([DIFF_EQUAL, bLines[bIndex]]);
    }
  };

  diffSequences(aLength, bLength, isCommon, foundSubsequence);

  for (; aIndex !== aLength; aIndex += 1) {
    diffs.push([DIFF_DELETE, aLines[aIndex]]);
  }
  for (; bIndex !== bLength; bIndex += 1) {
    diffs.push([DIFF_INSERT, bLines[bIndex]]);
  }

  return diffs;
}

export function addV2ErrorBoundary(tree: Tree, options: ErrorBoundarySchema) {
  insertImport(tree, options.path, `useRouteError`, '@remix-run/react');
  insertImport(tree, options.path, `isRouteErrorResponse`, '@remix-run/react');

  insertStatementAfterImports(
    tree,
    options.path,
    stripIndents`
    export function ErrorBoundary() {
        const error = useRouteError();

        // when true, this is what used to go to 'CatchBoundary'
        if (isRouteErrorResponse(error)) {
            return (
                <div>
                    <h1>Oops</h1>
                    <p>Status: {error.status}</p>
                    <p>{error.data.message}</p>
                </div>
            );
        } else if (error instanceof Error) {
            return (
                <div>
                    <h1>Error</h1>
                    <p>{error.message}</p>
                    <p>The stack trace is:</p>
                    <pre>{error.stack}</pre>
                </div>
            );
        } else {
            return <h1>Unknown Error</h1>;
        }
    }
  `
  );
}

export async function getRspackE2EWebServerInfo(
  tree: Tree,
  projectName: string,
  configFilePath: string,
  isPluginBeingAdded: boolean,
  e2ePortOverride?: number
) {
  const nxJson = readNxJson(tree);
  let e2ePort = e2ePortOverride ?? 4200;
  const servePort = readTargetDefaultsForTarget('serve', nxJson.targetDefaults)
    ?.options?.port;

  if (servePort) {
    e2ePort = servePort;
  }

  return getE2EWebServerInfo(
    tree,
    projectName,
    {
      plugin: '@nx/rspack/plugin',
      serveTargetName: 'serveTargetName',
      serveStaticTargetName: 'previewTargetName',
      configFilePath,
    },
    {
      defaultServeTargetName: 'serve',
      defaultServeStaticTargetName: 'preview',
      defaultE2EWebServerAddress: `http://localhost:${e2ePort}`,
      defaultE2ECiBaseUrl: `http://localhost:${e2ePort}`,
      defaultE2EPort: e2ePort,
    },
    isPluginBeingAdded
  );
}

export function reportMisc (
  log$: {
    registry: Rx.Observable<RegistryLog>
    other: Rx.Observable<Log>
  },
  opts: {
    appendOnly: boolean
    cwd: string
    logLevel?: LogLevel
    config?: Config
    zoomOutCurrent: boolean
  }
): Rx.Observable<Rx.Observable<{ msg: string }>> {
  const maxLogLevel = LOG_LEVEL_NUMBER[opts.logLevel ?? 'info'] ?? LOG_LEVEL_NUMBER['info']
  const reportWarning = makeWarningReporter(opts)
  return Rx.merge(log$.registry, log$.other).pipe(
    filter((obj) => LOG_LEVEL_NUMBER[obj.level] <= maxLogLevel &&
      (obj.level !== 'info' || !obj['prefix'] || obj['prefix'] === opts.cwd)),
    map((obj) => {
      switch (obj.level) {
        case 'warn': {
          return reportWarning(obj)
        }
        case 'error': {
          const errorOutput = reportError(obj, opts.config)
          if (!errorOutput) return Rx.NEVER
          if (obj['prefix'] && obj['prefix'] !== opts.cwd) {
            return Rx.of({
              msg: `${obj['prefix'] as string}:` + os.EOL + errorOutput,
            })
          }
          return Rx.of({ msg: errorOutput })
        }
        default:
          return Rx.of({ msg: obj.message! })
      }
    })
  )
}

function stringToBuffer(value: string, encoding: string) {
  encoding = encoding.toLowerCase() as Encoding

  if (encoding === 'utf8' || encoding === 'utf-8') {
    return new BufferClass(encoder.encode(value))
  }
  if (encoding === 'base64' || encoding === 'base64url') {
    value = value.replace(/-/g, '+').replace(/_/g, '/')
    value = value.replace(/[^A-Za-z0-9+/]/g, '')

    return new BufferClass([...atob(value)].map((v) => v.charCodeAt(0)))
  }
  if (encoding === 'binary' || encoding === 'ascii' || encoding === 'latin1' || encoding === 'latin-1') {
    return new BufferClass([...value].map((v) => v.charCodeAt(0)))
  }
  if (encoding === 'ucs2' || encoding === 'ucs-2' || encoding === 'utf16le' || encoding === 'utf-16le') {
    const buffer = new BufferClass(value.length * 2)
    const view = new DataView(buffer.buffer)
    for (let i = 0; i < value.length; i++) {
      view.setUint16(i * 2, value.charCodeAt(i), true)
    }
    return buffer
  }
  if (encoding === 'hex') {
    const bytes = new BufferClass(value.length / 2)
    for (let byteIndex = 0, i = 0; i < value.length; i += 2, byteIndex++) {
      bytes[byteIndex] = parseInt(value.slice(i, i + 2), 16)
    }

    return bytes
  }

  bufferPolyfillDoesNotImplement(`encoding "${encoding}"`)
}

function deepCloneValue(x: JsInputValue): JsInputValue {
  if (typeof x !== 'object' || x == null || isObjectEnumValue(x) || isFieldRef(x) || isSkip(x)) {
    return x
  }

  if (isDecimalJsLike(x)) {
    return new Decimal(x.toFixed())
  }

  if (isDate(x)) {
    return new Date(+x)
  }

  if (ArrayBuffer.isView(x)) {
    return x.slice(0)
  }

  if (Array.isArray(x)) {
    let k = x.length
    let copy
    for (copy = Array(k); k--; ) {
      copy[k] = deepCloneValue(x[k])
    }
    return copy
  }

  if (typeof x === 'object') {
    const copy = {}
    for (const k in x) {
      if (k === '__proto__') {
        Object.defineProperty(copy, k, {
          value: deepCloneValue(x[k]),
          configurable: true,
          enumerable: true,
          writable: true,
        })
      } else {
        copy[k] = deepCloneValue(x[k])
      }
    }
    return copy
  }

  assertNever(x, 'Unknown value')
}

createInputRules(): InputRule[] {
  const regexp = /^(\d+)\.\s$/;

  return [
    wrappingInputRule(
      regexp,
      this.type,
      (match) => ({ order: +assertGet(match, 1) }),
      (match, node) => node.childCount + (node.attrs.order as number) === +assertGet(match, 1),
    ),

    new InputRule(regexp, (state, match, start, end) => {
      const tr = state.tr;
      tr.deleteRange(start, end);
      const canUpdate = wrapSelectedItems({
        listType: this.type,
        itemType: assertGet(this.store.schema.nodes, 'listItem'),
        tr,
      });

      if (!canUpdate) {
        return null;
      }

      const order = +assertGet(match, 1);

      if (order !== 1) {
        const found = findParentNodeOfType({ selection: tr.selection, types: this.type });

        if (found) {
          tr.setNodeMarkup(found.pos, undefined, { order });
        }
      }

      return tr;
    }),
  ];
}

